package com.mystreet.api.config;
import com.mystreet.api.model.*;import com.mystreet.api.repo.*;import lombok.RequiredArgsConstructor;import org.springframework.boot.CommandLineRunner;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;import java.math.BigDecimal;
@Configuration @RequiredArgsConstructor public class DataSeeder { @Bean CommandLineRunner seed(UserRepository users,ProductRepository products,BCryptPasswordEncoder enc){return args->{ if(!users.existsByEmail("admin@mystreet.com")){User u=new User();u.setEmail("admin@mystreet.com");u.setPasswordHash(enc.encode("admin123"));u.setAdmin(true);users.save(u);} if(products.count()==0){String[][] data={{"Air Max 90","Nike","Classic retro vibe","119.99","airmax","7,8,9,10","50"},{"Ultraboost","Adidas","Responsive cushioning","139.99","ub","7,8,9,10,11","35"},{"Chuck Taylor","Converse","Canvas classic","59.99","chuck","6,7,8,9","40"},{"RS-X","Puma","Chunky street sneaker","89.99","rsx","7,8,9,10","30"},{"574","New Balance","Everyday comfort","84.99","574","8,9,10,11","25"},{"Classic Leather","Reebok","Clean leather style","74.99","reebok","7,8,9","45"},{"Old Skool","Vans","Skate icon","64.99","vans","6,7,8,9,10","38"},{"Gel-Kayano","Asics","Stable running shoe","129.99","kayano","8,9,10,11","20"}}; for(String[] d:data){Product p=new Product();p.setName(d[0]);p.setBrand(d[1]);p.setDescription(d[2]);p.setPrice(new BigDecimal(d[3]));p.setImageUrl("https://picsum.photos/seed/"+d[4]+"/500");p.setSizesCsv(d[5]);p.setStockQty(Integer.parseInt(d[6]));products.save(p);}}};}}
